section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/service-bootstrap-checklist.json",
  "type": "object",
  "title": "Service Bootstrap Checklist",
  "required": [
    "service_id",
    "checklist",
    "traffic_gate_open",
    "last_reviewed"
  ],
  "additionalProperties": false,
  "properties": {
    "service_id": {
      "type": "string",
      "minLength": 1,
      "description": "Service identifier."
    },
    "checklist": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Exactly 12 items: {id, name, owner, done, evidence_link, waiver_reason}."
    },
    "traffic_gate_open": {
      "type": "boolean",
      "description": "True only when all done OR waivers approved."
    },
    "platform_lead_approver": {
      "type": [
        "string",
        "null"
      ],
      "description": "Required if any waiver."
    },
    "last_reviewed": {
      "type": "string",
      "minLength": 1,
      "description": "ISO date."
    }
  }
}

example.code:
{
  "service_id": "svc-refunds",
  "checklist": [
    {
      "id": "repo",
      "name": "Repo created with CODEOWNERS",
      "owner": "alice",
      "done": true,
      "evidence_link": "https://github.com/org/svc-refunds",
      "waiver_reason": null
    }
  ],
  "traffic_gate_open": true,
  "platform_lead_approver": null,
  "last_reviewed": "2026-05-23"
}
